using Asp.Versioning;using Fixar.API.Security;using Fixar.Application.Common.Models;using Fixar.Domain.Entities;using Fixar.Infrastructure.Identity;using Fixar.Infrastructure.Persistence;using Microsoft.AspNetCore.Authorization;using Microsoft.AspNetCore.Mvc;using Microsoft.EntityFrameworkCore;namespace Fixar.API.Controllers;
[ApiController,ApiVersion("1.0"),Route("api/v{version:apiVersion}/supplier-payments"),Authorize(Policy=AuthorizationPolicies.CanViewSupplierFinance)]public class SupplierPaymentsController(ApplicationDbContext db):ControllerBase{
[HttpGet]public async Task<IActionResult>List(CancellationToken ct)=>Ok(ApiResponse<object>.SuccessResponse(await db.SupplierPayments.AsNoTracking().OrderByDescending(x=>x.PaymentDate).Select(x=>new{x.Id,x.PaymentNumber,x.SupplierId,SupplierName=x.Supplier.Name,x.PaymentDate,x.Currency,x.Amount,x.PaymentMethod,x.Status,x.UnallocatedAmount,x.FinancePostingStatus,x.IsReversed}).ToListAsync(ct)));
[HttpGet("{id:guid}")]public async Task<IActionResult>Detail(Guid id,CancellationToken ct){var x=await db.SupplierPayments.AsNoTracking().Where(x=>x.Id==id).Select(x=>new{x.Id,x.PaymentNumber,x.SupplierId,SupplierName=x.Supplier.Name,x.PaymentDate,x.Currency,x.Amount,x.PaymentMethod,x.FinancialAccountId,x.CustomerChequeId,x.FinancialTransactionId,x.Status,x.UnallocatedAmount,x.FinancePostingStatus,x.FinancePostingWarning,Allocations=x.Allocations.Select(a=>new{a.Id,a.SupplierPayableId,a.AllocatedAmount,a.Currency,a.AllocationDate,a.IsReversed})}).FirstOrDefaultAsync(ct);return x is null?NotFound():Ok(ApiResponse<object>.SuccessResponse(x));}
[HttpPut("{id:guid}"),Authorize(Policy=AuthorizationPolicies.CanRecordSupplierPayments)]public async Task<IActionResult>Update(Guid id,PaymentRequest r,CancellationToken ct){var p=await db.SupplierPayments.FindAsync([id],ct);if(p is null)return NotFound();if(p.Status!="Draft")return Conflict(ApiResponse<object>.Fail("Yalnız taslak ödeme düzenlenebilir.","LOCKED"));if(r.Amount<=0)return BadRequest();p.SupplierId=r.SupplierId;p.PaymentDate=r.PaymentDate.ToUniversalTime();p.Currency=r.Currency.ToUpper();p.Amount=r.Amount;p.UnallocatedAmount=r.Amount;p.PaymentMethod=r.PaymentMethod;p.FinancialAccountId=r.FinancialAccountId;p.CustomerChequeId=r.CustomerChequeId;p.ReferenceNumber=r.ReferenceNumber;p.Notes=r.Notes;await db.SaveChangesAsync(ct);return Ok(ApiResponse<object>.SuccessResponse(new{p.Id}));}
[HttpPost,Authorize(Policy=AuthorizationPolicies.CanRecordSupplierPayments)]public async Task<IActionResult>Create(PaymentRequest r,CancellationToken ct){if(r.Amount<=0)return BadRequest(ApiResponse<object>.Fail("Ödeme tutarı sıfırdan büyük olmalıdır.","VALIDATION"));if(!await db.Suppliers.AnyAsync(x=>x.Id==r.SupplierId,ct))return NotFound(ApiResponse<object>.Fail("Tedarikçi bulunamadı.","NOT_FOUND"));await using var tx=await db.Database.BeginTransactionAsync(ct);var x=new SupplierPayment{Id=Guid.NewGuid(),PaymentNumber=await SupplierFinanceSupport.Next(db,"SPY",r.PaymentDate,ct),SupplierId=r.SupplierId,PaymentDate=r.PaymentDate.ToUniversalTime(),Currency=r.Currency.ToUpper(),Amount=r.Amount,UnallocatedAmount=r.Amount,PaymentMethod=r.PaymentMethod,FinancialAccountId=r.FinancialAccountId,CustomerChequeId=r.CustomerChequeId,ReferenceNumber=r.ReferenceNumber,Notes=r.Notes,Status="Draft"};db.SupplierPayments.Add(x);await db.SaveChangesAsync(ct);await tx.CommitAsync(ct);return Ok(ApiResponse<object>.SuccessResponse(new{x.Id,x.PaymentNumber}));}
[HttpPost("{id:guid}/post"),Authorize(Policy=AuthorizationPolicies.CanRecordSupplierPayments),Idempotent]public async Task<IActionResult>Post(Guid id,CancellationToken ct){await using var tx=await db.Database.BeginTransactionAsync(ct);var x=await db.SupplierPayments.FirstOrDefaultAsync(x=>x.Id==id,ct);if(x is null)return NotFound();if(x.Status!="Draft")return Conflict(ApiResponse<object>.Fail("Ödeme daha önce post edildi.","POSTED"));if(x.PaymentMethod=="CustomerChequeEndorsement"){var ch=await db.CustomerCheques.FirstOrDefaultAsync(c=>c.Id==x.CustomerChequeId,ct);if(ch is null||ch.Status!="InPortfolio")return Conflict(ApiResponse<object>.Fail("Çek portföyde olmadığı için ciro edilemez.","CHEQUE_STATUS"));if(ch.Currency!=x.Currency)return Conflict(ApiResponse<object>.Fail("Ciro edilen çek ile ödeme para birimleri eşleşmiyor.","CURRENCY"));if(ch.Amount!=x.Amount)return Conflict(ApiResponse<object>.Fail("Kısmi çek cirosu desteklenmiyor.","PARTIAL_ENDORSEMENT"));if(await db.ChequeEndorsements.AnyAsync(e=>e.CustomerChequeId==ch.Id&&e.Status=="Active",ct))return Conflict(ApiResponse<object>.Fail("Bu çek daha önce başka bir tedarikçiye ciro edilmiş.","DUPLICATE"));var e=new ChequeEndorsement{Id=Guid.NewGuid(),EndorsementNumber=await SupplierFinanceSupport.Next(db,"END",x.PaymentDate,ct),CustomerChequeId=ch.Id,SupplierId=x.SupplierId,SupplierPaymentId=x.Id,EndorsementDate=x.PaymentDate,Currency=x.Currency,Amount=x.Amount,Status="Active",ReferenceNumber=x.ReferenceNumber,Created=DateTime.UtcNow};db.ChequeEndorsements.Add(e);ch.Status="EndorsedToSupplier";ch.EndorsedSupplierId=x.SupplierId;ch.SupplierPaymentId=x.Id;ch.EndorsedAt=DateTime.UtcNow;ch.EndorsementReference=x.ReferenceNumber;db.ChequeEvents.Add(new ChequeEvent{Id=Guid.NewGuid(),CustomerChequeId=ch.Id,EventType="Endorsed",EventDate=DateTime.UtcNow,PreviousStatus="InPortfolio",NewStatus="EndorsedToSupplier",ReferenceNumber=x.ReferenceNumber,Created=DateTime.UtcNow});x.FinancePostingStatus="NotRequired";}else if(x.PaymentMethod is "Cash" or "BankTransfer" or "CreditCard"||(x.PaymentMethod=="Other"&&x.FinancialAccountId.HasValue)){var a=await db.FinancialAccounts.FirstOrDefaultAsync(a=>a.Id==x.FinancialAccountId,ct);if(a is null)return NotFound(ApiResponse<object>.Fail("Finans hesabı bulunamadı.","ACCOUNT"));if(!a.IsActive||a.Currency!=x.Currency)return Conflict(ApiResponse<object>.Fail("Finans hesabı aktif değil veya para birimi eşleşmiyor.","ACCOUNT"));if(x.PaymentMethod=="Cash"&&a.AccountType!="Cash"||x.PaymentMethod=="BankTransfer"&&a.AccountType!="Bank")return Conflict(ApiResponse<object>.Fail("Ödeme yöntemi ile hesap türü eşleşmiyor.","TYPE"));var ft=await Finance(x,a,"Outflow","SupplierPayment",x.Id,ct);x.FinancialTransactionId=ft.Id;x.FinancePostingStatus="Posted";}else{x.FinancePostingStatus="Pending";x.FinancePostingWarning="Finans hesabına aktarılmamış ödeme.";}x.Status="Posted";db.SupplierLedgerEntries.Add(new SupplierLedgerEntry{Id=Guid.NewGuid(),EntryNumber=await SupplierFinanceSupport.Next(db,"SLE",x.PaymentDate,ct),SupplierId=x.SupplierId,TransactionDate=x.PaymentDate,EntryType="Debit",SourceType=x.PaymentMethod=="CustomerChequeEndorsement"?"ChequeEndorsement":"Payment",SourceId=x.Id,ReferenceNumber=x.PaymentNumber,Currency=x.Currency,DebitAmount=x.Amount,Created=DateTime.UtcNow});await db.SaveChangesAsync(ct);await tx.CommitAsync(ct);return Ok(ApiResponse<object>.SuccessResponse(new{x.Id,x.Status,x.FinancePostingStatus}));}
[HttpPost("{id:guid}/allocate"),Authorize(Policy=AuthorizationPolicies.CanAllocateSupplierPayments),Idempotent]public Task<IActionResult>Allocate(Guid id,PaymentAllocationRequest r,CancellationToken ct)=>AllocateCore(id,r.Lines,ct);
[HttpPost("{id:guid}/auto-allocate"),Authorize(Policy=AuthorizationPolicies.CanAllocateSupplierPayments),Idempotent]public async Task<IActionResult>Auto(Guid id,CancellationToken ct){var p=await db.SupplierPayments.AsNoTracking().FirstOrDefaultAsync(x=>x.Id==id,ct);if(p is null)return NotFound();var rem=p.UnallocatedAmount;var pays=await db.SupplierPayables.AsNoTracking().Where(x=>x.SupplierId==p.SupplierId&&x.Currency==p.Currency&&!x.IsCancelled&&x.OutstandingAmount>0).OrderByDescending(x=>x.DueDate<DateTime.UtcNow.Date).ThenBy(x=>x.DueDate).ThenBy(x=>x.TransactionDate).ToListAsync(ct);var lines=new List<PaymentAllocationLine>();foreach(var x in pays){if(rem<=0)break;var a=Math.Min(rem,x.OutstandingAmount);lines.Add(new(x.Id,a,null));rem-=a;}return await AllocateCore(id,lines,ct);}
[HttpGet("{id:guid}/allocation-suggestion")]public async Task<IActionResult>Suggestion(Guid id,CancellationToken ct){var p=await db.SupplierPayments.AsNoTracking().FirstOrDefaultAsync(x=>x.Id==id,ct);if(p is null)return NotFound();return Ok(ApiResponse<object>.SuccessResponse(await db.SupplierPayables.AsNoTracking().Where(x=>x.SupplierId==p.SupplierId&&x.Currency==p.Currency&&!x.IsCancelled&&x.OutstandingAmount>0).OrderBy(x=>x.DueDate).Select(x=>new{x.Id,x.PayableNumber,x.DueDate,x.OutstandingAmount}).ToListAsync(ct)));}
[HttpPost("{id:guid}/reverse"),Authorize(Policy=AuthorizationPolicies.CanReverseSupplierPayments),Idempotent]public async Task<IActionResult>Reverse(Guid id,CancelFinanceRequest r,CancellationToken ct){if(string.IsNullOrWhiteSpace(r.Reason))return BadRequest(ApiResponse<object>.Fail("Geri alma gerekçesi zorunludur.","REASON"));await using var tx=await db.Database.BeginTransactionAsync(ct);var p=await db.SupplierPayments.Include(x=>x.Allocations).ThenInclude(x=>x.SupplierPayable).FirstOrDefaultAsync(x=>x.Id==id,ct);if(p is null)return NotFound();if(p.IsReversed)return Conflict(ApiResponse<object>.Fail("Bu ödeme daha önce geri alınmış.","REVERSED"));foreach(var a in p.Allocations.Where(x=>!x.IsReversed)){a.IsReversed=true;a.ReversedAt=DateTime.UtcNow;a.SupplierPayable.AllocatedAmount-=a.AllocatedAmount;a.SupplierPayable.OutstandingAmount+=a.AllocatedAmount;a.SupplierPayable.Status=SupplierFinanceSupport.Status(a.SupplierPayable);}if(p.FinancialTransactionId.HasValue){var ft=await db.FinancialTransactions.Include(x=>x.FinancialAccount).FirstAsync(x=>x.Id==p.FinancialTransactionId,ct);var rev=await Finance(p,ft.FinancialAccount,"Inflow","Reversal",ft.Id,ct);ft.IsReversed=true;ft.ReversalTransactionId=rev.Id;}if(p.CustomerChequeId.HasValue){var ch=await db.CustomerCheques.FindAsync([p.CustomerChequeId.Value],ct);var e=await db.ChequeEndorsements.FirstOrDefaultAsync(x=>x.SupplierPaymentId==p.Id&&x.Status=="Active",ct);if(ch is not null){ch.Status="InPortfolio";ch.EndorsedSupplierId=null;ch.SupplierPaymentId=null;}if(e is not null){e.Status="Reversed";e.IsReversed=true;e.ReversalReason=r.Reason;}}db.SupplierLedgerEntries.Add(new SupplierLedgerEntry{Id=Guid.NewGuid(),EntryNumber=await SupplierFinanceSupport.Next(db,"SLE",DateTime.UtcNow,ct),SupplierId=p.SupplierId,TransactionDate=DateTime.UtcNow,EntryType="Credit",SourceType="Reversal",SourceId=p.Id,ReferenceNumber=p.PaymentNumber,Currency=p.Currency,CreditAmount=p.Amount,Description=r.Reason,Created=DateTime.UtcNow});p.IsReversed=true;p.Status="Reversed";p.ReversalReason=r.Reason;await db.SaveChangesAsync(ct);await tx.CommitAsync(ct);return Ok(ApiResponse<object>.SuccessResponse(new{p.Id,p.Status}));}
[HttpPost("{id:guid}/cancel"),Authorize(Policy=AuthorizationPolicies.CanRecordSupplierPayments),Idempotent]public async Task<IActionResult>Cancel(Guid id,CancelFinanceRequest r,CancellationToken ct){var p=await db.SupplierPayments.FindAsync([id],ct);if(p is null)return NotFound();if(p.Status!="Draft")return Conflict();p.Status="Cancelled";await db.SaveChangesAsync(ct);return Ok(ApiResponse<object>.SuccessResponse(new{p.Id,p.Status}));}
[HttpGet("summary")]public async Task<IActionResult>Summary(CancellationToken ct)=>Ok(ApiResponse<object>.SuccessResponse(await db.SupplierPayments.AsNoTracking().Where(x=>!x.IsReversed&&x.Status!="Draft"&&x.Status!="Cancelled").GroupBy(x=>x.Currency).Select(g=>new{Currency=g.Key,Paid=g.Sum(x=>x.Amount),Unallocated=g.Sum(x=>x.UnallocatedAmount),Endorsed=g.Where(x=>x.PaymentMethod=="CustomerChequeEndorsement").Sum(x=>(decimal?)x.Amount)??0}).ToListAsync(ct)));
async Task<IActionResult>AllocateCore(Guid id,IReadOnlyList<PaymentAllocationLine>lines,CancellationToken ct){await using var tx=await db.Database.BeginTransactionAsync(ct);var p=await db.SupplierPayments.FirstOrDefaultAsync(x=>x.Id==id,ct);if(p is null)return NotFound();if(p.Status is not("Posted" or "PartiallyAllocated"))return Conflict(ApiResponse<object>.Fail("Ödeme post edilmeden dağıtım yapılamaz.","STATUS"));if(lines.Sum(x=>x.Amount)>p.UnallocatedAmount)return Conflict(ApiResponse<object>.Fail("Dağıtım tutarı ödemenin kalan miktarını aşıyor.","OVER"));foreach(var l in lines){var pay=await db.SupplierPayables.FirstOrDefaultAsync(x=>x.Id==l.PayableId,ct);if(pay is null)return NotFound();if(pay.SupplierId!=p.SupplierId||pay.Currency!=p.Currency)return Conflict(ApiResponse<object>.Fail("Ödeme ve borç para birimleri eşleşmiyor.","MATCH"));if(l.Amount>pay.OutstandingAmount)return Conflict(ApiResponse<object>.Fail("Dağıtım tutarı borcun açık miktarını aşıyor.","OVER"));db.SupplierPaymentAllocations.Add(new SupplierPaymentAllocation{Id=Guid.NewGuid(),SupplierPaymentId=p.Id,SupplierPayableId=pay.Id,PurchaseOrderId=pay.PurchaseOrderId,AllocatedAmount=l.Amount,Currency=p.Currency,AllocationDate=DateTime.UtcNow,Notes=l.Notes,Created=DateTime.UtcNow});pay.AllocatedAmount+=l.Amount;pay.OutstandingAmount-=l.Amount;pay.Status=SupplierFinanceSupport.Status(pay);p.UnallocatedAmount-=l.Amount;}p.Status=p.UnallocatedAmount==0?"FullyAllocated":"PartiallyAllocated";await db.SaveChangesAsync(ct);await tx.CommitAsync(ct);return Ok(ApiResponse<object>.SuccessResponse(new{p.Id,p.Status,p.UnallocatedAmount}));}
async Task<FinancialTransaction>Finance(SupplierPayment p,FinancialAccount a,string dir,string type,Guid source,CancellationToken ct){await db.Database.ExecuteSqlRawAsync("SELECT pg_advisory_xact_lock(81311)",ct);var prefix=$"FTX-{DateTime.UtcNow:yyyyMMdd}-";var vals=await db.FinancialTransactions.Where(x=>x.TransactionNumber.StartsWith(prefix)).Select(x=>x.TransactionNumber).ToListAsync(ct);var n=vals.Select(x=>int.TryParse(x[prefix.Length..],out var i)?i:0).DefaultIfEmpty().Max()+1;var ft=new FinancialTransaction{Id=Guid.NewGuid(),TransactionNumber=$"{prefix}{n:0000}",FinancialAccountId=a.Id,TransactionDate=DateTime.UtcNow,TransactionType=type,Direction=dir,SourceType="SupplierPayment",SourceId=source,Currency=p.Currency,Amount=p.Amount,Description=p.PaymentNumber,ReferenceNumber=p.ReferenceNumber,Created=DateTime.UtcNow};db.FinancialTransactions.Add(ft);return ft;}}
public record PaymentRequest(Guid SupplierId,DateTime PaymentDate,string Currency,decimal Amount,string PaymentMethod,Guid?FinancialAccountId,Guid?CustomerChequeId,string?ReferenceNumber,string?Notes);public record PaymentAllocationRequest(List<PaymentAllocationLine>Lines);public record PaymentAllocationLine(Guid PayableId,decimal Amount,string?Notes);
